const filePath = $input.item.json.path || $input.item.json.file || $input.item.json.filePath;
const normalised = filePath.replace(/\//g, '\\');
const parts = normalised.split('\\');
const fileName = parts[parts.length - 1];
const folderName = (parts[parts.length - 2] || '').toLowerCase().trim();
const ext = fileName.split('.').pop().toLowerCase();
const baseName = fileName.replace(new RegExp('\\.' + ext + '$', 'i'), '');
const timestamp = Date.now();
const outputFileName = baseName + '_p1_' + timestamp + '.' + ext;

// CONFIGURE THIS: Update folder names and blur levels to match your persona config
const blurMap = {
  'your_content_type_1': { level: ''none'',       needsBlur: false, vaultOnly: false },
  ''your_content_type_2'': { level: ''light'',      needsBlur: false, vaultOnly: false },
  ''your_content_type_3'': { level: ''moderate'',   needsBlur: true,  vaultOnly: false },
  ''your_content_type_4'': { level: ''aggressive'', needsBlur: true,  vaultOnly: false },
  ''private'':             { level: ''none'',       needsBlur: false, vaultOnly: true  },
};

const cfg = blurMap[folderName] || { level: 'light', needsBlur: false, vaultOnly: false };

return {
  filePath,
  fileName,
  folderName,
  ext,
  baseName,
  outputFileName,
  blurLevel: cfg.level,
  needsBlur: cfg.needsBlur,
  vaultOnly: cfg.vaultOnly,
  instagramPath: (process.env.CONTENT_BASE || '/data/content') + '/_approved/instagram/' + outputFileName,
  xPath:         (process.env.CONTENT_BASE || '/data/content') + '/_approved/x/' + outputFileName,
  threadsPath:   (process.env.CONTENT_BASE || '/data/content') + '/_approved/threads/' + outputFileName,
  ofReadyPath:   (process.env.CONTENT_BASE || '/data/content') + '/_vault/OF_ready/' + outputFileName,
};

const fs = require('fs');
const path = require('path');
const { filePath, ofReadyPath, folderName } = $input.item.json;

const dir = path.dirname(ofReadyPath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
fs.copyFileSync(filePath, ofReadyPath);

console.log('[VAULT ONLY] ' + folderName + ' content copied to OF_ready: ' + ofReadyPath);
return {
  ...$input.item.json,
  action: 'vault_only',
  result: 'NSFW content moved to OF_ready vault. Not posted.',
};

// ============================================================
// NODE: Vision + Blur + Vault Copy
// Reads image, calls GPT-4o Vision for blur regions,
// applies Sharp blur, saves to instagram + OF_ready.
// ============================================================
const sharp = require('sharp');
const fs = require('fs');
const path = require('path');

const input = $input.item.json;
const { filePath, instagramPath, ofReadyPath, blurLevel, ext, needsBlur } = input;

// --- Step 1: Read file as base64 ---
const imageBuffer = fs.readFileSync(filePath);
const base64 = imageBuffer.toString('base64');
const mimeMap = { jpg:'image/jpeg', jpeg:'image/jpeg', png:'image/png', webp:'image/webp', heic:'image/heic', gif:'image/gif' };
const mime = mimeMap[ext] || 'image/jpeg';

// --- Step 2: GPT-4o Vision blur detection ---
const blurInstructions = {
  aggressive: 'This is pole dance/dance content. Be very aggressive. Flag ALL: visible skin areas (arms, legs, torso, back, midriff, chest region), body-revealing clothing, suggestive poses. Return bounding boxes for EVERY such region.',
  moderate:   'This is outfit/activewear content. Flag: visible midriff, low necklines, form-fitting areas showing significant body shape, bare legs above knee.',
  light:      'Only flag explicit nudity or content that clearly violates Instagram community guidelines.',
  none:       'This content is safe. Return empty regions array.',
};
const instruction = blurInstructions[blurLevel] || blurInstructions['light'];

const OPENAI_KEY = process.env.OPENAI_API_KEY || $env.OPENAI_API_KEY;

const visionRes = await fetch('https://api.openai.com/v1/chat/completions', {
  method: 'POST',
  headers: { 'Authorization': 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'gpt-4o',
    messages: [{
      role: 'user',
      content: [
        { type: 'image_url', image_url: { url: 'data:' + mime + ';base64,' + base64 } },
        { type: 'text', text: 'You are an Instagram content safety analyzer.\n\n' + instruction + '\n\nReturn ONLY valid JSON (no markdown, no explanation):\n{"needsBlur":true/false,"regions":[{"x":number,"y":number,"width":number,"height":number}],"safeForInstagram":true/false}' }
      ]
    }],
    max_tokens: 800,
  })
});

const visionData = await visionRes.json();
const visionText = visionData.choices?.[0]?.message?.content || '{"needsBlur":false,"regions":[]}';

let blurRegions = [];
let safeForInstagram = true;
try {
  const cleaned = visionText.replace(/```json\n?|\n?```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  blurRegions = parsed.regions || [];
  safeForInstagram = parsed.safeForInstagram !== false;
} catch(e) {
  console.log('[WARN] Vision parse error — no blur applied:', e.message);
}

// --- Step 3: Ensure output dirs exist ---
[path.dirname(instagramPath), path.dirname(ofReadyPath)].forEach(dir => {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
});

// --- Step 4: Apply blur and save Instagram version ---
if (blurRegions.length > 0 && needsBlur !== false) {
  const imageSharp = sharp(filePath);
  const meta = await imageSharp.metadata();
  const overlays = blurRegions
    .filter(r => r.width > 0 && r.height > 0 && r.x < (meta.width||9999) && r.y < (meta.height||9999))
    .map(region => ({
      input: Buffer.from('<svg width="' + region.width + '" height="' + region.height + '"><rect width="' + region.width + '" height="' + region.height + '" fill="rgba(180,180,180,0.85)" rx="4"/></svg>'),
      blend: 'over',
      left: Math.max(0, Math.round(region.x)),
      top:  Math.max(0, Math.round(region.y)),
    }));

  await sharp(filePath)
    .composite(overlays)
    .blur(20)
    .toFile(instagramPath);

  console.log('[BLUR] Applied ' + overlays.length + ' blur region(s) -> ' + instagramPath);
} else {
  await sharp(filePath).toFile(instagramPath);
  console.log('[COPY] No blur needed -> ' + instagramPath);
}

// --- Step 5: Copy original to OF_ready ---
fs.copyFileSync(filePath, ofReadyPath);
console.log('[VAULT] Original copied to OF_ready -> ' + ofReadyPath);

return {
  ...input,
  blurRegions,
  blurApplied: blurRegions.length > 0,
  blurCount: blurRegions.length,
  safeForInstagram,
  instagramReady: true,
  vaultReady: true,
  visionRaw: visionText,
};

// ============================================================
// NODE: Generate 3 Captions via GPT-4o
// Uses creator voice brief.
// ============================================================
const input = $input.item.json;
const { folderName, fileName } = input;

const OPENAI_KEY = process.env.OPENAI_API_KEY || $env.OPENAI_API_KEY;

const captionRes = await fetch('https://api.openai.com/v1/chat/completions', {
  method: 'POST',
  headers: { 'Authorization': 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: 'You are the exclusive caption writer for a bold, classy, sensual lifestyle creator. Voice brief: CONFIGURE THIS: Replace this with your persona's voice brief from config/persona.example.json. The AI writes every caption in exactly this voice. Return ONLY valid JSON, no markdown.'
      },
      {
        role: 'user',
        content: 'Generate exactly 3 caption options for ' + folderName + ' content. Return ONLY this JSON:\n{\n  "captions": ["caption1", "caption2", "caption3"],\n  "hashtags": ["#tag1", "#tag2", "#tag3", "#tag4", "#tag5", "#tag6", "#tag7"]\n}'
      }
    ],
    max_tokens: 600,
  })
});

const captionData = await captionRes.json();
const captionText = captionData.choices?.[0]?.message?.content || '{"captions":["","",""],"hashtags":[]}';

let captions = ['Caption 1 (parse error)', 'Caption 2 (parse error)', 'Caption 3 (parse error)'];
let hashtags = [];
try {
  const cleaned = captionText.replace(/```json\n?|\n?```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  captions = parsed.captions || captions;
  hashtags = parsed.hashtags || hashtags;
} catch(e) {
  console.log('[WARN] Caption parse error:', e.message);
}

// CONFIGURE THIS: Update with your folders and preferred posting times
const timeMap = {
  dance:       '8:00 PM',
  fits:        '12:00 PM',
  'yoga pants':'7:00 AM',
  coffee:      '9:00 AM',
  concerts:    '10:00 PM',
  nature:      '6:00 AM',
  house:       '2:00 PM',
  fam:         '11:00 AM',
};
const suggestedTime = timeMap[folderName] || '6:00 PM';

return {
  ...input,
  captions,
  hashtags,
  suggestedTime,
};

// ============================================================
// NODE: Save Pending Approval + Send WhatsApp via Twilio
// Stores approval state to JSON file, sends WhatsApp message.
// ============================================================
const fs = require('fs');
const input = $input.item.json;
const { folderName, captions, hashtags, suggestedTime, instagramPath, ofReadyPath, fileName, outputFileName } = input;

const TWILIO_SID      = process.env.TWILIO_ACCOUNT_SID   || $env.TWILIO_ACCOUNT_SID;
const TWILIO_TOKEN    = process.env.TWILIO_AUTH_TOKEN     || $env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM     = process.env.TWILIO_WHATSAPP_FROM  || $env.TWILIO_WHATSAPP_FROM  || 'whatsapp:+14155238886';
const TWILIO_TO       = process.env.TWILIO_WHATSAPP_TO    || $env.TWILIO_WHATSAPP_TO;
const N8N_WEBHOOK_URL = process.env.N8N_WEBHOOK_URL       || $env.N8N_WEBHOOK_URL || 'YOUR_NGROK_URL/webhook/approval-handler';

// --- Build approval message ---
const msg = [
  '\ud83d\udd25 content_creator \u2014 Post Ready',
  '',
  '\ud83d\udcc1 Category: ' + folderName,
  '\ud83d\udcc5 Suggested time: ' + suggestedTime,
  '\ud83c\udf10 Platforms: Instagram + X + Threads',
  '',
  'Caption 1: ' + captions[0],
  'Caption 2: ' + captions[1],
  'Caption 3: ' + captions[2],
  '',
  'Reply:',
  'Y1 \u2014 Post with caption 1',
  'Y2 \u2014 Post with caption 2',
  'Y3 \u2014 Post with caption 3',
  'N  \u2014 Skip this post',
  'E  \u2014 I\'ll write my own caption',
].join('\n');

// --- Save pending approval to file ---
const pendingFilePath = (process.env.SCRIPTS_DIR || '/data/scripts') + '/pending_approvals.json';
let pending = {};
try {
  if (fs.existsSync(pendingFilePath)) {
    pending = JSON.parse(fs.readFileSync(pendingFilePath, 'utf8'));
  }
} catch(e) { /* start fresh */ }

const approvalId = 'p1_' + Date.now();
pending[approvalId] = {
  id:            approvalId,
  fileName,
  outputFileName,
  folderName,
  instagramPath,
  ofReadyPath,
  captions,
  hashtags,
  suggestedTime,
  status:        'pending',
  createdAt:     new Date().toISOString(),
};
fs.writeFileSync(pendingFilePath, JSON.stringify(pending, null, 2));
console.log('[STATE] Saved pending approval:', approvalId);

// --- Send WhatsApp via Twilio ---
const twilioUrl = 'https://api.twilio.com/2010-04-01/Accounts/' + TWILIO_SID + '/Messages.json';
const creds = Buffer.from(TWILIO_SID + ':' + TWILIO_TOKEN).toString('base64');

const twilioRes = await fetch(twilioUrl, {
  method: 'POST',
  headers: { 'Authorization': 'Basic ' + creds, 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({ From: TWILIO_FROM, To: TWILIO_TO, Body: msg }).toString(),
});
const twilioData = await twilioRes.json();

console.log('[WHATSAPP] Sent:', twilioData.sid || JSON.stringify(twilioData));

return {
  ...input,
  approvalId,
  whatsappSent: !!twilioData.sid,
  twilioMessageSid: twilioData.sid,
  approvalMessage: msg,
  status: 'awaiting_approval',
};
